interface.definition:
a!localVariables(
  local!inmate: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418098"(userName: loggedInUser()),
  local!existingCurrentAllowanceRequest: #"SYSTEM_SYSRULES_queryRecordType_v2"(
    recordType: #"urn:appian:record-type:v1:869b0f23-8e42-4780-8dfc-89deb24c798d",
    filters: #"SYSTEM_SYSRULES_queryLogicalExpression"(
      operator: "AND",
      filters: {
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2e6a1a3-9952-4aee-a7d5-c5077d3fb9be",
          operator: "=",
          value: local!inmate[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/d70d7a0c-0ee6-4949-84d6-2c58d8caffcc"]
        ),
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/13ac8f18-8fd8-4341-8f42-86db1aaa8588",
          operator: "=",
          value: year(today())
        ),
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/c705d2d0-bbc1-404a-bbc5-93cffc1a8c52",
          operator: "=",
          value: month(today())
        )
      }
    ),
    pagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(1, 1, #"SYSTEM_SYSRULES_sortInfo"(#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/ab4316cc-3bee-4bb9-b663-14ee81dc52b3", false)),
    fetchTotalCount: true
  ),
  local!last3Months: #"SYSTEM_SYSRULES_forEach"(
    items: enumerate(3),
    expression: todate(a!subtractDateTime(startDateTime: now(), months: fv!index-1))
  ),
  local!monthYearOptions: #"SYSTEM_SYSRULES_forEach"(
    items: local!last3Months,
    expression: {
      label: text(fv!item, "MMMM yyyy"),
      value: fv!item
    }
  ),
  local!selectedMonthYear,
  #"SYSTEM_SYSRULES_formLayout_v1"(
    label: #"urn:appian:translation-string:v1:1fa26928-81fe-4a66-9662-cf3a61741d20",
    contents: if(
      local!existingCurrentAllowanceRequest.totalCount >= #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1495500",
      #"SYSTEM_SYSRULES_boxLayout"(
        label: #"urn:appian:translation-string:v1:a237999b-6b38-4b5f-b623-61ecc7192e9d",
        contents: #"SYSTEM_SYSRULES_richTextDisplayField"(
          value: #"SYSTEM_SYSRULES_richTextItem_v1"(
            text: #"urn:appian:translation-string:v1:ea74f91a-8c7b-485f-b674-3eaefb179ae0" & ": " &
            local!existingCurrentAllowanceRequest.data[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2219542-a8b5-464d-9306-5654dce49a83"]
          )
        ),
        style: "WARN"
      ),
      {
        #"SYSTEM_SYSRULES_columnsLayout"(
          columns: { 
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "1X"
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              contents: {
                #"SYSTEM_SYSRULES_columnsLayout"(
                  columns: {
                    #"SYSTEM_SYSRULES_columnLayout"(contents: {
                      #"SYSTEM_SYSRULES_richTextDisplayField"(
                        value: {
                          #"urn:appian:translation-string:v1:047ca7b5-95c2-421c-96cf-a6f2be811230"

                        },
                        align: "CENTER",
                        marginAbove: "LESS",
                        marginBelow: "MORE"
                      )
                    }, width: "5X"),
                    #"SYSTEM_SYSRULES_columnLayout"( contents: {
                      #"SYSTEM_SYSRULES_dropdownField_v1"(
                        choiceLabels: index(local!monthYearOptions, "label", {}),
                        choiceValues: index(local!monthYearOptions, "value", {}),
                        label: "",
                        placeholder: "-- " & #"urn:appian:translation-string:v1:442f59db-4d5f-4099-969d-5e3bdcf5b47a"& " --", 
                        value: local!selectedMonthYear,
                        saveInto: local!selectedMonthYear
                      )
                    }, width: "2X"),
                    #"SYSTEM_SYSRULES_columnLayout"(
                      width: "1X"
                    )
                  }
                ),
                #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
                  text: {
                    #"urn:appian:translation-string:v1:fb7f3a70-caa5-4d10-ace8-4f0d50adf246",
                    #"urn:appian:translation-string:v1:d185410b-77e9-4d79-847f-a3a077b4cb2d"
                  },
                  label: #"urn:appian:translation-string:v1:63c774cf-5f27-490b-90ae-53f22a550fde"
                )
              },
              width: "10X"
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "1X"
            )        
          }
        )
      }
    ),
    buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
      primaryButtons: #"SYSTEM_SYSRULES_buttonWidget_v1"(
        label: #"urn:appian:translation-string:v1:f77c5ad7-1935-44cc-a63e-843733004e30",
        saveInto: {
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/0158bc6e-dc82-471e-b662-acc363b9ba87"],
            value: false
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/4399f51f-64fe-4714-9e9e-3b30238666ed"],
            value: loggedInUser()
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2219542-a8b5-464d-9306-5654dce49a83"],
            value: now()
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/c705d2d0-bbc1-404a-bbc5-93cffc1a8c52"],
            value: month(local!selectedMonthYear)
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/13ac8f18-8fd8-4341-8f42-86db1aaa8588"],
            value: year(local!selectedMonthYear)
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/b7965e68-ff18-4b2f-8f7b-efb3fb5e298b"],
            value: now()
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/746e407a-2a3a-4a00-b4fc-59b2103b6131"],
            value: loggedInUser()
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/f3ba344c-c6d8-48a9-b57e-2ac2380a8f74"],
            value: now()
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2e6a1a3-9952-4aee-a7d5-c5077d3fb9be"],
            value: local!inmate[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/d70d7a0c-0ee6-4949-84d6-2c58d8caffcc"]
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af"],
            value: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1411841"
          ),
          a!save(
            target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/8f6e62d6-f646-45a8-a038-e356580cbf87"],
            value: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1417768"
          )
        },
        submit: true, 
        style: "SOLID",
        disabled: local!existingCurrentAllowanceRequest.totalCount >= #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1495500",
        validate: true
      ),
      secondaryButtons: #"SYSTEM_SYSRULES_buttonWidget_v1"(
        label: #"urn:appian:translation-string:v1:d940fe67-4bc0-43d9-9eca-be0aa0394b8a",
        saveInto: a!save(target: ri!cancel, value: true),
        submit: true,
        validate: false
      )
    )
  )
)
